var e=[{id:`L3_1`,type:`dialog`,speaker:`ROSE_BETA_MAID_NULL`,text:{KOREA:`꽃은 꺾이거나 시들면, 언제든 대체될 수 있는 존재죠.`,JPN:`花は折れたり枯れると、いつでも代わりがきく存在です。`,ENG:`Flowers, when plucked or wilted, are easily replaced.`,TWN:`花朵凋零或枯萎時，只要換上新的就好。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ROSE_BETA_MAID_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`ROSE_BETA_MAID_NULL`,text:{KOREA:`따라서 마스터를 모시는 저희에게 이름 같은 건 없습니만… 마스터께서 기꺼이 이름을 바라신다면, 저희를 로즈라고 불러주세요.`,JPN:`それゆえ、マスターに仕える私たちに名前などないのですが……もしマスターが名前をお望みなら、私たちをローズとお呼びください。`,ENG:`That is why we, who exist to serve you, carry no names... But if you so wish to call us something, Master, then let us be Rose.`,TWN:`我們之於主人亦是如此，因此我們沒有名字…但主人願意的話，可以叫我們玫瑰。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`ROSE_BETA_MAID_NULL`,face:`UNIT_LAUGH`}}}},{id:`L5_1`,type:`dialog`,speaker:`ROSE_BETA_MAID_NULL`,text:{KOREA:`저희의 모든 삶은 오직 당신만을 위해 존재하기에.`,JPN:`私たちのすべての生は、ただ貴方だけのために存在しますので。`,ENG:`Our lives exist solely for you.`,TWN:`因為我們一生就只單單為主人而活。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ROSE_BETA_MAID_NULL`,face:`UNIT_PRIDE`},C:null,R:null}}}];export{e as default};